#include <stdio.h>
#include <semaphore.h>

/* == EXEMPLE ===============================================
 * Semaphore binaire : controler l'acces a un compteur
 * Init=1 signifie 'libre', sem_wait acquiert, sem_post libere.
 * ========================================================= */
int resource_count = 0;

void example_binary_sem(void) {
    sem_t gate;
    sem_init(&gate, 0, 1);
    int v;
    sem_getvalue(&gate, &v);
    printf("gate before: %d\n", v);
    sem_wait(&gate);
    resource_count++;
    printf("resource_count = %d\n", resource_count);
    sem_post(&gate);
    sem_getvalue(&gate, &v);
    printf("gate after: %d\n", v);
    sem_destroy(&gate);
}
/* Resultat: gate before: 1, resource_count = 1, gate after: 1 */

